    // TAG avec photo du groupe ─────────────────
    tag: async (sock, from, msg, args) => {
        if (!isGroup(from)) return reply(sock, from, "❌ Groupe seulement.", msg);
        const meta = await sock.groupMetadata(from);
        const members = meta.participants.map(p => p.id);
        const customMsg = args.join(" ") || `${NEON} Attention tout le monde!`;
        let text =
            `${NEON}━━━━━━━━━━━━━━━━━━${NEON}\n` +
            `*${customMsg}*\n` +
            `${NEON}━━━━━━━━━━━━━━━━━━${NEON}\n\n` +
            `🏢 *${meta.subject}*\n` +
            `👥 *${members.length} membres*\n\n`;
        for (const m of members) text += `@${shortNum(m)} `;
        // Essayer avec photo du groupe
        try {
            const ppUrl = await sock.profilePictureUrl(from, "image");
            const res = await fetch(ppUrl);
            const buf = Buffer.from(await res.arrayBuffer());
            await sock.sendMessage(from, { image: buf, caption: text, mentions: members }, { quoted: msg });
        } catch (_) {
            await sock.sendMessage(from, { text, mentions: members }, { quoted: msg });
        }
    },

