    kickall: async (sock, from, msg, args, sender) => {
        if (!isOwner(sender)) return reply(sock, from, "❌ Owner seulement.", msg);
        if (!isGroup(from)) return reply(sock, from, "❌ Groupe seulement.", msg);
        const meta = await sock.groupMetadata(from);
        const botJid = sock.user.id;
        const targets = meta.participants.filter(p =>
            !p.admin && !isOwner(p.id) && shortNum(p.id) !== shortNum(botJid)
        );
        if (!targets.length) return reply(sock, from, "❌ Aucun membre non-admin a expulser.", msg);
        await reply(sock, from, `${SKULL} Expulsion de *${targets.length}* membres...`, msg);
        let count = 0;
        for (const m of targets) {
            try { await sock.groupParticipantsUpdate(from, [m.id], "remove"); count++; await wait(600); } catch (_) {}
        }
        await reply(sock, from, `${CYBER} *${count}* expulse(s). Admins restes.`, msg);
    },

