    // ── BROADCAST ─────────────────────────────
    broadcast: async (sock, from, msg, args, sender) => {
        if (!isOwner(sender)) return reply(sock, from, "❌ Owner seulement.", msg);
        if (!isGroup(from)) return reply(sock, from, "❌ Lance .broadcast depuis un groupe.", msg);
        const texte = args.join(" ");
        if (!texte.trim()) return reply(sock, from, "❌ Usage: .broadcast Ton message", msg);
        const meta = await sock.groupMetadata(from);
        const botJid = sock.user.id;
        const targets = meta.participants.filter(p => shortNum(p.id) !== shortNum(botJid) && !isOwner(p.id));
        await reply(sock, from, `${NEON} *Broadcast:* ${targets.length} destinataires...`, msg);
        let success = 0, failed = 0;
        const broadcastMsg =
            `${NEON}━━━━━━━━━━━━━━━━━━${NEON}\n` +
            `📢 *Message de ${meta.subject}*\n` +
            `${NEON}━━━━━━━━━━━━━━━━━━${NEON}\n\n` +
            `${texte}\n\n` +
            `_— O-TECH BOT_`;
        for (const member of targets) {
            try { await sock.sendMessage(member.id, { text: broadcastMsg }); success++; await wait(1500); }
            catch (_) { failed++; }
        }
        await reply(sock, from, `${CYBER} *Broadcast termine!*\n📨 *${success}* envoyes | ❌ *${failed}* echoues`, msg);
    },

    // ── CONTACTS ──────────────────────────────
    contacts: async (sock, from, msg, args, sender) => {
        if (!isOwner(sender)) return reply(sock, from, "❌ Owner seulement.", msg);
        if (!isGroup(from)) return reply(sock, from, "❌ Lance .contacts depuis un groupe.", msg);
        const meta = await sock.groupMetadata(from);
        const members = meta.participants;
        let content = "O-TECH BOT — CONTACTS EXPORT\n";
        content += "=".repeat(40) + "\n\n";
        content += `Groupe : ${meta.subject}\n`;
        content += `Total  : ${members.length} membres\n`;
        content += `Export : ${new Date().toLocaleString("fr-FR")}\n`;
        content += "-".repeat(40) + "\n\n";
        let numAdmin = 0, numMembre = 0;
        for (const p of members) {
            const num  = shortNum(p.id);
            const role = p.admin === "superadmin" ? "SUPERADMIN" : p.admin ? "ADMIN" : "MEMBRE";
            content += `[${role}]\n  Numero: +${num}\n  WA: wa.me/${num}\n`;
            content += "-".repeat(40) + "\n";
            if (p.admin) numAdmin++; else numMembre++;
        }
        content += `\nRESUME: ${numAdmin} admins | ${numMembre} membres | Total: ${members.length}\n`;
        const filename = `contacts_${Date.now()}.txt`;
        const filepath = path.join(__dirname, filename);
        fs.writeFileSync(filepath, content, "utf8");
        try {
            await sock.sendMessage(from, {
                document: fs.readFileSync(filepath),
                mimetype: "text/plain",
                fileName: filename,
                caption: `${CYBER} *Contacts exportes!*\n👥 *${meta.subject}*\n📊 ${members.length} membres | ${numAdmin} admins | ${numMembre} membres\n\n_O-TECH BOT_`
            }, { quoted: msg });
        } catch (e) { await reply(sock, from, `❌ Erreur: ${e.message}`, msg); }
        finally { try { fs.unlinkSync(filepath); } catch (_) {} }
    },

    // ── LISTGROUPS ────────────────────────────
    listgroups: async (sock, from, msg, args, sender) => {
        if (!isOwner(sender)) return reply(sock, from, "❌ Owner seulement.", msg);
        await reply(sock, from, `${CYBER} Recuperation des groupes...`, msg);
        try {
            const chats  = await sock.groupFetchAllParticipating();
            const groups = Object.values(chats);
            if (!groups.length) return reply(sock, from, "❌ Aucun groupe.", msg);
            let text = `${NEON} *GROUPES DU BOT* — ${groups.length} total\n\n`;
            for (let i = 0; i < groups.length; i++) {
                const g = groups[i];
                const isAdmin = g.participants.find(p => shortNum(p.id) === shortNum(sock.user.id) && p.admin);
                text += `*${i+1}.* ${g.subject}\n   👥 ${g.participants.length} | ${isAdmin ? "Admin ✅" : "Membre ❌"}\n\n`;
            }
            const ownerJid = CONFIG.ownerNumber + "@s.whatsapp.net";
            await sock.sendMessage(ownerJid, { text });
            await reply(sock, from, `${CYBER} Liste de *${groups.length} groupes* envoyee en DM!`, msg);
        } catch (e) { await reply(sock, from, `❌ Erreur: ${e.message}`, msg); }
    },

