    // POLL — sondage interactif ────────────────
    poll: async (sock, from, msg, args, sender) => {
        if (!isGroup(from)) return reply(sock, from, "❌ Groupe seulement.", msg);
        const raw = args.join(" ");
        const parts = raw.split("|").map(s => s.trim()).filter(Boolean);
        if (parts.length < 3) return reply(sock, from, "❌ Usage: .poll Question | Option1 | Option2 ...", msg);
        const question = parts[0];
        const options  = parts.slice(1);
        const key = `poll_${from}`;
        const votes = {};
        options.forEach((_, i) => votes[i] = []);
        pollSessions.set(key, { question, options, votes, creator: sender });
        const nums = ["1️⃣","2️⃣","3️⃣","4️⃣","5️⃣","6️⃣"];
        let text = `${NEON} *SONDAGE O-TECH*\n\n❓ *${question}*\n\n`;
        options.forEach((opt, i) => text += `${nums[i]} ${opt}\n`);
        text += `\n_Vote avec .vote 1/2/3..._\n_Resultat: .result_`;
        await reply(sock, from, text, msg);
    },

    vote: async (sock, from, msg, args, sender) => {
        if (!isGroup(from)) return reply(sock, from, "❌ Groupe seulement.", msg);
        const key = `poll_${from}`;
        const session = pollSessions.get(key);
        if (!session) return reply(sock, from, "❌ Pas de sondage actif. Tape .poll", msg);
        const choice = parseInt(args[0]) - 1;
        if (isNaN(choice) || choice < 0 || choice >= session.options.length)
            return reply(sock, from, `❌ Choix invalide. Vote de 1 a ${session.options.length}`, msg);
        // Retirer vote precedent
        for (const votes of Object.values(session.votes)) {
            const idx = votes.indexOf(sender);
            if (idx !== -1) votes.splice(idx, 1);
        }
        session.votes[choice].push(sender);
        await reply(sock, from, `${CYBER} Vote enregistre: *${session.options[choice]}*`, msg);
    },

    result: async (sock, from, msg) => {
        if (!isGroup(from)) return reply(sock, from, "❌ Groupe seulement.", msg);
        const key = `poll_${from}`;
        const session = pollSessions.get(key);
        if (!session) return reply(sock, from, "❌ Pas de sondage actif.", msg);
        const total = Object.values(session.votes).reduce((s, v) => s + v.length, 0);
        const nums = ["1️⃣","2️⃣","3️⃣","4️⃣","5️⃣","6️⃣"];
        let text = `${NEON} *RESULTATS*\n\n❓ *${session.question}*\n\n`;
        session.options.forEach((opt, i) => {
            const count = session.votes[i].length;
            const pct = total > 0 ? Math.round(count / total * 100) : 0;
            const bar = "█".repeat(Math.round(pct/10)) + "░".repeat(10 - Math.round(pct/10));
            text += `${nums[i]} *${opt}*\n[${bar}] ${pct}% (${count})\n\n`;
        });
        text += `_Total votes: ${total}_`;
        await reply(sock, from, text, msg);
    },

