    // ── MÉDIAS ────────────────────────────────
    vv: async (sock, from, msg) => {
        const ctx = msg.message?.extendedTextMessage?.contextInfo;
        const stanzaId = ctx?.stanzaId;
        let stored = stanzaId ? viewOnceStore.get(stanzaId) : null;
        if (!stored && ctx?.quotedMessage) {
            const qm = ctx.quotedMessage;
            const vo = qm?.viewOnceMessage?.message || qm?.viewOnceMessageV2?.message || qm?.viewOnceMessageV2Extension?.message;
            if (vo) {
                try {
                    const mediaMsg = vo.imageMessage || vo.videoMessage;
                    const mediaType = vo.imageMessage ? "image" : "video";
                    if (mediaMsg) {
                        const stream = await downloadContentFromMessage(mediaMsg, mediaType);
                        const chunks = [];
                        for await (const chunk of stream) chunks.push(chunk);
                        stored = { type: mediaType, buffer: Buffer.concat(chunks), sender: ctx?.participant || from };
                    }
                } catch (_) {}
            }
        }
        if (!stored) return reply(sock, from, "❌ View once introuvable.", msg);
        const caption = `${NEON} *View Once*\n_De:_ @${shortNum(stored.sender)}`;
        await sock.sendMessage(from, stored.type === "image"
            ? { image: stored.buffer, caption, mentions: [stored.sender] }
            : { video: stored.buffer, caption, mentions: [stored.sender] }, { quoted: msg });
    },

    send: async (sock, from, msg) => {
        const ctx = msg.message?.extendedTextMessage?.contextInfo;
        if (!ctx?.quotedMessage) return reply(sock, from, "❌ Reponds a un message avec .send", msg);
        const qm = ctx.quotedMessage;
        const type = Object.keys(qm)[0];
        try {
            if (type === "imageMessage") {
                const buf = await downloadContentFromMessage(qm.imageMessage, "image").then(async s => { const c=[]; for await(const ch of s) c.push(ch); return Buffer.concat(c); });
                await sock.sendMessage(from, { image: buf, caption: qm.imageMessage.caption || "📸" }, { quoted: msg });
            } else if (type === "videoMessage") {
                const buf = await downloadContentFromMessage(qm.videoMessage, "video").then(async s => { const c=[]; for await(const ch of s) c.push(ch); return Buffer.concat(c); });
                await sock.sendMessage(from, { video: buf, caption: qm.videoMessage.caption || "🎥" }, { quoted: msg });
            } else if (type === "audioMessage") {
                const buf = await downloadContentFromMessage(qm.audioMessage, "audio").then(async s => { const c=[]; for await(const ch of s) c.push(ch); return Buffer.concat(c); });
                await sock.sendMessage(from, { audio: buf, mimetype: "audio/mp4", ptt: false }, { quoted: msg });
            } else {
                const text = qm.conversation || qm.extendedTextMessage?.text || "";
                await reply(sock, from, `📝 *Statut:*\n\n${text}`, msg);
            }
        } catch (e) { await reply(sock, from, `❌ Erreur: ${e.message}`, msg); }
    },

